def extract_rows(d, keys):
    rows = []

    def walk(obj):
        if isinstance(obj, dict):
            row = {k: obj.get(k) for k in keys}
            if any(v is not None for v in row.values()):
                rows.append(row)

            for v in obj.values():
                walk(v)

    walk(d)
    return rows

